USE project6;

-- UUID constants for the 10 seed users
SET @u1  = '00000000-0000-4000-a000-000000000001';
SET @u2  = '00000000-0000-4000-a000-000000000002';
SET @u3  = '00000000-0000-4000-a000-000000000003';
SET @u4  = '00000000-0000-4000-a000-000000000004';
SET @u5  = '00000000-0000-4000-a000-000000000005';
SET @u6  = '00000000-0000-4000-a000-000000000006';
SET @u7  = '00000000-0000-4000-a000-000000000007';
SET @u8  = '00000000-0000-4000-a000-000000000008';
SET @u9  = '00000000-0000-4000-a000-000000000009';
SET @u10 = '00000000-0000-4000-a000-000000000010';

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE photos;
TRUNCATE TABLE comments;
TRUNCATE TABLE albums;
TRUNCATE TABLE todos;
TRUNCATE TABLE posts;
TRUNCATE TABLE passwords;
TRUNCATE TABLE users;
SET FOREIGN_KEY_CHECKS = 1;

